import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Tooltip } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import BusCharts from "./BusCharts"; // assuming your chart component

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const [filter, setFilter] = useState("All");
  const [showChart, setShowChart] = useState(false);

  // Fetch buses every 2 minutes
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const res = await fetch("http://127.0.0.1:8000/buses");
        const data = await res.json();
        setBuses(data.buses || []);
      } catch (err) {
        console.error("Error fetching buses:", err);
      }
    };

    fetchBuses(); // initial fetch
    const interval = setInterval(fetchBuses, 2 * 60 * 1000); // 2 minutes

    return () => clearInterval(interval);
  }, []);

  // Count different bus statuses
  const runningCount = buses.filter((b) => b.status === "Running").length;
  const ghostCount = buses.filter((b) => b.status === "Ghost").length;
  const anomalyCount = buses.filter((b) => b.status === "Anomaly").length;

  // Filtered buses
  const filteredBuses = buses.filter((b) => {
    if (filter === "All") return true;
    return b.status === filter;
  });

  return (
    <div style={{ height: "100vh", width: "100%", position: "relative" }}>
      {/* Filter and Chart buttons */}
      <div
        style={{
          position: "absolute",
          top: 12,
          left: 50,
          background: "rgba(255,255,255,0.95)",
          padding: "8px 12px",
          borderRadius: "8px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
          zIndex: 1000,
          fontSize: "14px",
        }}
      >
        <label>
          Show:{" "}
          <select value={filter} onChange={(e) => setFilter(e.target.value)}>
            <option value="All">All</option>
            <option value="Running">Running</option>
            <option value="Ghost">Ghost</option>
            <option value="Anomaly">Anomaly</option>
          </select>
        </label>
        <button
          style={{ marginLeft: "10px" }}
          onClick={() => setShowChart(!showChart)}
        >
          {showChart ? "Hide Chart" : "Show Chart"}
        </button>
      </div>

      {/* Bus counts */}
      <div
        style={{
          position: "absolute",
          bottom: 10,
          left: 10,
          background: "rgba(255,255,255,0.9)",
          padding: "8px 12px",
          borderRadius: "8px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
          zIndex: 1000,
          fontSize: "14px",
        }}
      >
        🟢 Running: {runningCount} <br />
        🔴 Ghost: {ghostCount} <br />
        🟠 Anomaly: {anomalyCount}
      </div>

      {/* Map */}
      <MapContainer
        center={[40.7128, -74.006]}
        zoom={12}
        style={{ height: "100%", width: "100%" }}
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a>'
          url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
          subdomains={["a", "b", "c", "d"]}
        />

        {filteredBuses.map((bus, index) => (
          <CircleMarker
            key={`${bus.feed}-${bus.id}-${bus.lat}-${bus.lon}`} // unique key
            center={[bus.lat, bus.lon]}
            radius={6}
            fillOpacity={1}
            color={
              bus.status === "Running"
                ? "green"
                : bus.status === "Ghost"
                ? "red"
                : "orange"
            }
          >
            <Tooltip>
              <div>
                <strong>Bus ID:</strong> {bus.id} <br />
                <strong>Feed:</strong> {bus.feed} <br />
                <strong>Status:</strong> {bus.status} <br />
                <strong>Speed:</strong>{" "}
                {bus.speed ? bus.speed.toFixed(1) + " mph" : "N/A"}
              </div>
            </Tooltip>
          </CircleMarker>
        ))}
      </MapContainer>

      {/* Chart toggle */}
      {showChart && (
        <div
          style={{
            position: "absolute",
            top: 60,
            left: 50,
            width: "400px",
            height: "250px",
            background: "rgba(255,255,255,0.95)",
            padding: "10px",
            borderRadius: "8px",
            boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
            zIndex: 1000,
          }}
        >
          <BusCharts buses={buses} />
        </div>
      )}
    </div>
  );
}
